import { memo } from "react";
import { BookOpen } from "lucide-react";
import { cn } from "@/lib/utils";
import { ThumbRow } from "./parts/thumb-row";
import { ThumbListEmpty } from "./parts/empty-state";
import { THUMB_LIST_DEFAULT_LABELS, type ThumbList01Props } from "./types";

function ThumbList01Inner(props: ThumbList01Props) {
  const {
    items,
    framed = true,
    headingAs: HeadingTag = "h3",
    headerIcon = BookOpen,
    linkComponent = "a",
    renderMeta,
    emptyState,
    labels,
    className,
    headerClassName,
    itemClassName,
    imageClassName,
    titleClassName,
    metaClassName,
  } = props;

  const resolvedLabels = { ...THUMB_LIST_DEFAULT_LABELS, ...labels };
  const HeaderIcon = headerIcon;
  const isEmpty = items.length === 0;

  return (
    <section
      className={cn(
        framed && "bg-card rounded-2xl p-6 border border-border/50",
        className
      )}
    >
      <HeadingTag
        className={cn(
          "text-lg font-serif font-bold text-foreground mb-4 flex items-center gap-2",
          headerClassName
        )}
      >
        {HeaderIcon ? (
          <HeaderIcon className="w-5 h-5 text-primary" aria-hidden="true" />
        ) : null}
        {resolvedLabels.heading}
      </HeadingTag>

      {isEmpty ? (
        <ThumbListEmpty
          custom={emptyState}
          message={resolvedLabels.emptyText}
        />
      ) : (
        <ul className="space-y-4">
          {items.map((item) => (
            <ThumbRow
              key={item.id}
              item={item}
              linkComponent={linkComponent}
              renderMeta={renderMeta}
              itemClassName={itemClassName}
              imageClassName={imageClassName}
              titleClassName={titleClassName}
              metaClassName={metaClassName}
            />
          ))}
        </ul>
      )}
    </section>
  );
}

export const ThumbList01 = memo(ThumbList01Inner);
ThumbList01.displayName = "ThumbList01";

export { ThumbList01 } from "./thumb-list-01";
export {
  THUMB_LIST_DEFAULT_LABELS,
  type ThumbListItem,
  type ThumbList01Labels,
  type ThumbList01Props,
} from "./types";
export { meta } from "./meta";

import type { ComponentType, ElementType, ReactNode } from "react";

export interface ThumbListItem {
  id: string;
  title: string;
  imageSrc: string;
  imageAlt?: string;
  meta?: string;
  href?: string;
}

export interface ThumbList01Labels {
  heading?: string;
  emptyText?: string;
}

export interface ThumbList01Props {
  items: ReadonlyArray<ThumbListItem>;
  framed?: boolean;
  headingAs?: "h2" | "h3" | "h4";
  headerIcon?: ComponentType<{ className?: string }> | null;
  linkComponent?: ElementType;
  renderMeta?: (item: ThumbListItem) => ReactNode;
  emptyState?: ReactNode;
  labels?: ThumbList01Labels;
  className?: string;
  headerClassName?: string;
  itemClassName?: string;
  imageClassName?: string;
  titleClassName?: string;
  metaClassName?: string;
}

export const THUMB_LIST_DEFAULT_LABELS: Required<ThumbList01Labels> = {
  heading: "Related",
  emptyText: "Nothing here yet.",
};

import type { ElementType, ReactNode } from "react";
import { cn } from "@/lib/utils";
import type { ThumbListItem } from "../types";

interface ThumbRowProps {
  item: ThumbListItem;
  linkComponent: ElementType;
  renderMeta?: (item: ThumbListItem) => ReactNode;
  itemClassName?: string;
  imageClassName?: string;
  titleClassName?: string;
  metaClassName?: string;
}

export function ThumbRow({
  item,
  linkComponent: LinkEl,
  renderMeta,
  itemClassName,
  imageClassName,
  titleClassName,
  metaClassName,
}: ThumbRowProps) {
  const meta = renderMeta
    ? renderMeta(item)
    : item.meta
      ? (
        <p className={cn("text-xs text-muted-foreground mt-1", metaClassName)}>
          {item.meta}
        </p>
      )
      : null;

  const inner = (
    <>
      <img
        src={item.imageSrc}
        alt={item.imageAlt ?? item.title}
        loading="lazy"
        className={cn(
          "w-20 h-16 rounded-lg object-cover shrink-0",
          imageClassName
        )}
      />
      <div className="min-w-0">
        <p
          className={cn(
            "text-sm font-medium text-foreground line-clamp-2",
            "group-hover:text-primary group-focus-visible:text-primary transition-colors",
            titleClassName
          )}
        >
          {item.title}
        </p>
        {meta}
      </div>
    </>
  );

  return (
    <li className={cn("group", itemClassName)}>
      {item.href ? (
        <LinkEl
          href={item.href}
          className="flex gap-3 items-start rounded-md focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
        >
          {inner}
        </LinkEl>
      ) : (
        <div className="flex gap-3 items-start">{inner}</div>
      )}
    </li>
  );
}

import type { ReactNode } from "react";

interface ThumbListEmptyProps {
  custom?: ReactNode;
  message: string;
}

export function ThumbListEmpty({ custom, message }: ThumbListEmptyProps) {
  if (custom !== undefined && custom !== null) {
    return <>{custom}</>;
  }
  return (
    <p
      className="text-sm text-muted-foreground"
      role="status"
      aria-live="polite"
    >
      {message}
    </p>
  );
}
